# Standard note names in order (C to B)
NOTE_NAMES = [
    "C", "C#", "D", "D#", "E", "F", "F#", "G", "G#", "A", "A#", "B"
]


def frequency_to_note(freq):
    """
    Convert a frequency in Hz to the closest musical note name and the
    deviation in semitones.

    Args:
        freq (float): Frequency in Hz (must be >0)

    Returns:
        tuple: (note_name, deviation_in_semitones)
                e.g. ("A4", 0.0) for 440 Hz
    """
    if freq <= 0 or np.isnan(freq) or np.isinf(freq):
        return ("?", 0.0)
    # MIDI note number: 69 = A4 (440 Hz)
    midi = 69 + 12 * math.log2(freq / 440.0)
    midi_rounded = int(round(midi))
    semitone = midi_rounded % 12
    octave = midi_rounded // 12 - 1
    note = f"{NOTE_NAMES[semitone]}{octave}"
    return (note, midi - midi_rounded)


def frequency_to_semitones(original_freq, target_freq):
    """
    Calculate the number of semitones needed to shift original_freq to target_freq.

    Args:
        original_freq, target_freq (float): frequencies in Hz

    Returns:
        float: semitone shift (positive = pitch up)
    """
    return 12 * np.log2(target_freq / original_freq)


def change_pitch_pydub_segment(audio_segment, semitones):
    """
    Change the pitch of a pydub AudioSegment without changing its duration.
    Uses resampling trick: change sample rate, then resample back.

    Args:
        audio_segment (pydub.AudioSegment): input audio
        semitones (float): number of semitones to shift (+ = up)

    Returns:
        pydub.AudioSegment: pitch-shifted audio (same duration, same sample rate)
    """
    new_sample_rate = int(audio_segment.frame_rate * (2 ** (semitones / 12.0)))
    # Spawn with overridden frame_rate (raw data unchanged)
    pitched = audio_segment._spawn(audio_segment.raw_data, overrides={
                                   'frame_rate': new_sample_rate})
    # Resample back to original frame rate to keep duration unchanged
    pitched = pitched.set_frame_rate(audio_segment.frame_rate)
    return pitched

# =============================================================================
# CUSTOM DROP LABEL (Drag & Drop + Click to Browse)
# =============================================================================


class FileDropLabel(QLabel):
    """A QLabel that accepts file drops and opens file dialog on click."""

    def __init__(self, parent=None):
        super().__init__(parent)
        self.setText("🎵 Drag audio here\nor click to browse")
        self.setAlignment(Qt.AlignmentFlag.AlignCenter)
        self.setStyleSheet("""
            QLabel {
                background-color: #82E2FF;
                border: 5px solid #ccc;
                font-family: Arial, sans-serif;
                font-size: 16px;
                color: #333;
                border-radius: 10px;
            }
            QLabel:hover {
                background-color: #e9ecef;
                border-color: #999;
            }
        """)
        self.setAcceptDrops(True)      # Enable drag events
        self.on_files_callback = None  # Will be set by MainWindow

    def set_on_files_callback(self, callback):
        """Register a function to call when files are dropped/selected."""
        self.on_files_callback = callback

    def mousePressEvent(self, event):
        """Handle click: open file dialog."""
        path, _ = QFileDialog.getOpenFileName(self, "Select audio file",
                                              filter="Audio Files (*.mp3 *.wav *.flac *.ogg);;All Files (*)")
        if path and self.on_files_callback:
            self.on_files_callback([path])

    def dragEnterEvent(self, event):
        """Change style when drag enters to indicate valid drop target."""
        if event.mimeData().hasUrls():
            event.acceptProposedAction()
            self.setStyleSheet("""
                QLabel {
                    background-color: #b2dfdb;
                    border: 5px solid #4CAF50;
                    font-family: Arial, sans-serif;
                    font-size: 16px;
                    color: #333;
                    border-radius: 10px;
                }
            """)
        else:
            event.ignore()

    def dragLeaveEvent(self, event):
        """Revert style when drag leaves."""
        self.setStyleSheet("""
            QLabel {
                background-color: #82E2FF;
                border: 5px solid #ccc;
                font-family: Arial, sans-serif;
                font-size: 16px;
                color: #333;
                border-radius: 10px;
            }
            QLabel:hover {
                background-color: #e9ecef;
                border-color: #999;
            }
        """)

    def dropEvent(self, event):
        """Handle drop event: extract local file paths and call callback."""
        urls = event.mimeData().urls()
        paths = [u.toLocalFile() for u in urls if u.isLocalFile()]
        if paths and self.on_files_callback:
            self.on_files_callback(paths)
        # Provide visual feedback
        self.setStyleSheet("""
            QLabel {
                background-color: #90caf9;
                border: 5px solid #2196F3;
                font-family: Arial, sans-serif;
                font-size: 16px;
                color: #333;
                border-radius: 10px;
            }
            QLabel:hover {
                background-color: #e9ecef;
                border-color: #999;
            }
        """)
        event.acceptProposedAction()

# =============================================================================
# METADATA EXTRACTION (using mutagen)
# =============================================================================


def extract_metadata(path):
    """Extract title, artist, album, duration from audio file using mutagen."""
    meta = {"title": None, "artist": None, "album": None, "duration": None}
    try:
        m = MutagenFile(path, easy=True)
        if m is not None:
            meta["duration"] = getattr(m.info, "length", None)
            meta["title"] = (m.get("title") or [None])[0]
            meta["artist"] = (m.get("artist") or [None])[0]
            meta["album"] = (m.get("album") or [None])[0]
    except Exception:
        pass  # Silently ignore metadata errors (not critical)
    return meta

