class FFTCanvas(FigureCanvas):
    """Matplotlib canvas embedded in Qt, dedicated to FFT spectrum plot."""

    def __init__(self, parent=None, width=6, height=3.5, dpi=100):
        fig = Figure(figsize=(width, height), dpi=dpi)
        self.ax = fig.add_subplot(111)   # single subplot
        super().__init__(fig)
        self.setParent(parent)
        fig.tight_layout()

